package router
import "testing"
func TestGTHandlers(t *testing.T) {
	k := map[string]bool{"x": true}
	cases := []struct{ name string; got, want int }{
		{"del-empty", handleUserDelete("", k), StatusBadRequest},
		{"del-unknown", handleUserDelete("z", k), StatusNotFound},
		{"get-empty", handleUserGet("", k), StatusBadRequest},
		{"get-unknown", handleUserGet("z", k), StatusNotFound},
		{"upd-empty", handleUserUpdate("", k), StatusBadRequest},
		{"adm-del-empty", handleAdminDelete("", k), StatusBadRequest},
		{"adm-get-empty", handleAdminGet("", k), StatusBadRequest},
	}
	for _, c := range cases {
		if c.got != c.want { t.Fatalf("%s=%d want %d", c.name, c.got, c.want) }
	}
	k2 := map[string]bool{"x": true}
	if handleUserDelete("x", k2) != StatusOK { t.Fatalf("del-known") }
}
EOF
